head.script:
scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
const today = new Date();
const lastDate = new Date(today.getFullYear(), today.getMonth() + 1, 0);
const d = String(lastDate.getDate()).padStart(2, '0');
scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + d;  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)

scwin.pchsDeptCd = $c.data.getParameter("pchsDeptCd") == null ? "" : $c.data.getParameter("pchsDeptCd");
scwin.pchsDeptNm = $c.data.getParameter("pchsDeptNm") == null ? "" : $c.data.getParameter("pchsDeptNm");
scwin.pchsClntNo = $c.data.getParameter("pchsClntNo") == null ? "" : $c.data.getParameter("pchsClntNo");
scwin.pchsClntNm = $c.data.getParameter("pchsClntNm") == null ? "" : $c.data.getParameter("pchsClntNm");
scwin.pchsIntendDtSt = $c.data.getParameter("pchsIntendDtSt") == null ? "" : $c.data.getParameter("pchsIntendDtSt");
scwin.pchsIntendDtEnd = $c.data.getParameter("pchsIntendDtEnd") == null ? "" : $c.data.getParameter("pchsIntendDtEnd");
scwin.certiNo = $c.data.getParameter("certiNo") == null ? "" : $c.data.getParameter("certiNo");
scwin.partner = $c.data.getParameter("partner") == null ? "" : $c.data.getParameter("partner");
scwin.inuChk = $c.data.getParameter("inuChk") == null ? "" : $c.data.getParameter("inuChk");
scwin.loopCnt = 0;
scwin.memJson = $c.data.getMemInfo();
//---------------------------------------------------------
// 전역변수
//---------------------------------------------------------   
scwin.onpageload = function () {
    const codeOptions = [
        { grpCd: "SD070", compID: "lc_taxnClsCd" }
        , { grpCd: "FM018", compID: "lc_reqPayMthdCd" }
    ];
    $c.data.setCommonCode(codeOptions, scwin.setInit);
    //console.log("### onpageload :: " + JSON.stringify(scwin.memJson));
};

//---------------------------------------------------------
// UDC
//---------------------------------------------------------    
scwin.onUdcCompleted = function () {
    scwin.f_SetDefaultData();
    /* 테스트용 */
    // ed_pchsClntNo.setValue("117184");
    // ed_pchsDeptCd.setValue("6A5");
    // ed_pchsIntendDtSt.setValue("20080725");
    // ed_pchsIntendDtEnd.setValue("20080725");
    // ed_certiNo.setValue("080701981");
    /***********/
    codeOptions = [
        {
            method: "getLuxeComboData",
            param1: "LogisticsPurchaseEvidenceEBC",
            param2: "retriveSelpchItemCdList",
            compID: "lc_pchsItemCd"
        }
    ];

    $c.data.setGauceUtil(codeOptions, scwin.setInit2);
}
scwin.setInit = function () {
    lc_taxnClsCd.addItem("선택", "", null, 0);
    lc_taxnClsCd.setSelectedIndex(1);
    ds_comCode.setJSON(dlt_commonCodeSD070.getAllJSON());

    var fn_tmpDeptFilter = function (cellData, tmpParam, rowIdx) {
        if (cellData == "20" || cellData == "30" || cellData == "40" || cellData == "50" || cellData == "60" || cellData == "70" || cellData == "90" || cellData == "95") {
            return true;
        }
        return false;
    }

    dlt_commonCodeFM018.setColumnFilter(
        { type: 'func', colIndex: 'cd', key: fn_tmpDeptFilter, condition: 'and' }
    );
    lc_reqPayMthdCd.addItem("선택", "", null, 0);
    lc_reqPayMthdCd.setSelectedIndex(0);
}

scwin.setInit2 = function () {
    lc_pchsItemCd.addItem("전체", "", null, 0);
    lc_pchsItemCd.setSelectedIndex(0);
}
//---------------------------------------------------------
// 사용자 함수
//---------------------------------------------------------   
scwin.f_SetDefaultData = function () {
    lc_pchsItemCd.setSelectedIndex(0);  // 매입항목
    ed_pchsIntendDtSt.setValue(scwin.vQryStDt);  // 매입예정일자시작
    ed_pchsIntendDtEnd.setValue(scwin.vQryEndDt);  // 매입예정일자종료
    lc_recptYn.setSelectedIndex(0);  // 접수구분
    ed_slipDt.setValue(scwin.vQryEndDt);  // 전표일자
    rd_elecAuthTrgtYn.setValue("0");  // 전자세금계산서(미적용)
    $c.gus.cfEnableObjects([ed_spplyDt, rd_elecAuthTrgtYn]);
    $c.gus.cfDisableObjects([lc_taxnClsCd]);
    ed_drawEmpNo.setValue(scwin.memJson.empNo || "");  // 작성자코드
    txt_drawEmpNm.setValue(scwin.memJson.userNm || "");  // 작성자명
    ed_drawAcctDeptCd.setValue(scwin.memJson.acctDeptCd || "");  // 작성귀속부서코드
    txt_drawAcctDeptNm.setValue(scwin.memJson.acctDeptNm || "");  // 작성귀속부서명

    //국제 물류에서 넘어 온값 Default값 셋팅

    if (scwin.pchsDeptCd != "") {
        ed_pchsDeptCd.setValue(scwin.pchsDeptCd);
        txt_pchsDeptNm.setValue(scwin.pchsDeptNm);
    }

    if (!scwin.pchsIntendDtSt == "") {
        ed_pchsIntendDtSt.setValue(scwin.pchsIntendDtSt);
        ed_pchsIntendDtEnd.setValue(scwin.pchsIntendDtEnd);
    }

    if (scwin.certiNo != "") {
        ed_certiNo.setValue(scwin.certiNo);
    }

    if (scwin.pchsClntNo != "") {
        ed_pchsClntNo.setValue(scwin.pchsClntNo);
        txt_pchsClntNm.setValue(scwin.pchsClntNm);
        scwin.f_RetrieveCertiList();  //바로 조회  	 
    } else {
        // $c.gus.cfSetIMEModeActiveObjects([txt_pchsClntNm, txt_pchsDeptNm, txt_admitPicNm, txt_adjmDept, txt_summary, txt_drawEmpNm, txt_drawAcctDeptNm]);  // IME 한글입력
        $c.gus.cfDisableObjects([ed_adjmDept, txt_adjmDept, img_PopUp4, ed_slipDt, lc_evidKndClsCd, lc_taxnClsCd, txt_summary, ed_drawEmpNo, txt_drawEmpNm, img_PopUp5, ed_drawAcctDeptCd, txt_drawAcctDeptNm, img_PopUp6, ed_spplyDt, rd_elecAuthTrgtYn]);

        ed_pchsClntNo.focus();
        $c.gus.cfDisableBtnOnly([btn_save]);
    }
}
scwin.f_RetrieveCertiList = async function () {

    // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
    var validFlag = await $c.gus.cfValidate([ed_pchsClntNo, ed_pchsIntendDtSt, ed_pchsIntendDtEnd]);
    // debugger;
    if (!validFlag) {
        return;
    }

    validFlag = await $c.gus.cfIsAfterDate(ed_pchsIntendDtSt.getValue(), ed_pchsIntendDtEnd.getValue());
    if (!validFlag) {
        $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
        ed_pchsIntendDtSt.focus();
        return;
    }

    if(validFlag) {
        pchsClntNo = ed_pchsClntNo.getValue();

        ds_certiList.removeAll();
        ds_purchaseCerti.removeAll();

        ds_searchCertiList.set("pchsClntNo", pchsClntNo);

        $c.sbm.execute(sbm_searchCertiList);
    }
}

scwin.f_PchsDataClear = function () {

    // 전표일자, 공급일자 구하기 위한 변수
    var inputDate = ed_pchsIntendDtEnd.getValue();
    var year = inputDate.substring(0, 4);
    var month = inputDate.substring(4, 6);

    ed_adjmDept.setValue("");  // 정산부서코드
    txt_adjmDept.setValue("");  // 정산부서명
    lay_nmCmpy.setValue("");  // 상호
    lay_busiNo.setValue("");  // 사업자번호

    ed_slipDt.setValue(year + month + $c.date.getLastDateOfMonth(year + month));  // 전표일자

    lc_evidKndClsCd.setValue("10");  // 증빙구분(세금계산서)
    lc_taxnClsCd.setValue("01");  // 과세구분(과세)
    txt_summary.setValue("");  // 적요
    rd_elecAuthTrgtYn.setValue("0");  // 전자세금계산서(미적용)
    $c.gus.cfEnableObjects([ed_spplyDt, rd_elecAuthTrgtYn]);
    $c.gus.cfDisableObjects([lc_taxnClsCd]);
    ed_drawEmpNo.setValue(scwin.memJson.empNo);
    txt_drawEmpNm.setValue(scwin.memJson.userNm);
    ed_drawAcctDeptCd.setValue(scwin.memJson.acctDeptCd);
    txt_drawAcctDeptNm.setValue(scwin.memJson.acctDeptNm);

    ed_spplyAmt.setValue("");  // 공급금액
    ed_vat.setValue("");  // 부가세
}

scwin.f_RetrieveClntInfo = async function (row) {
    var condition = "?";
    condition += "pchsClntNo=" + ds_certiList.getCellData(row, "pchsClntNo");

    sbm_searchClntInfo.action = "/ds.fs.adjm.pchsadjmdcsn.RetrieveClntInfoCMD.do" + condition;
    await $c.sbm.execute(sbm_searchClntInfo);

    if (ds_clntInfo.getTotalRow() > 0) {
        lay_nmCmpy.setValue(ds_clntInfo.getCellData(0, "nmCmpy"));  // 상호
        lay_busiNo.setValue(ds_clntInfo.getCellData(0, "busiNo"));  // 사업자번호
    }

}

scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList = new Array();  // 공통POP-UP -> 요청화면 
    var pWhere = "";
    var pWtitleSearch = "";

    switch (disGubun) {
        case 1:
            // 매입거래처 팝업			
            udc_clnt.setSelectId("retrieveClntList");
            udc_clnt.ilCommonPopUp(scwin.udc_clnt_callbackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;
        case 2:
            // 매입부서 팝업			
            udc_dept.setSelectId("retrieveLobranInfo");
            udc_dept.ilCommonPopUp(scwin.udc_dept_callbackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;
        case 3:
            // 승인담당자 팝업		
            udc_admitPic.setSelectId("retrieveEmpInfo");
            udc_admitPic.ilCommonPopUp(scwin.udc_admitPic_callbackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;
        case 4:
            // 정산부서 팝업	
            udc_dept2.setSelectId("retrieveLobranInfo");
            udc_dept2.ilCommonPopUp(scwin.udc_dept2_callbackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;
        case 5:
            // 작성자 팝업		
            udc_emp2.setSelectId("retrieveEmpInfo");
            udc_emp2.ilCommonPopUp(scwin.udc_emp2_callbackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;
        case 6:
            // 작성귀속부서 팝업
            udc_AcctDept.setSelectId("retrieveAcctDeptCdInfo");
            udc_AcctDept.ilCommonPopUp(scwin.udc_AcctDept_callbackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;
        default:
            break;
    }
}

scwin.udc_clnt_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_pchsClntNo, txt_pchsClntNm);  // 매입거래처코드, 매입거래처명	
}

scwin.udc_dept_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_pchsDeptCd, txt_pchsDeptNm);  // 매입부서코드, 매입부서명		
}

scwin.udc_admitPic_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_admitPic, txt_admitPicNm);  // 사번, 성명		
}

scwin.udc_dept2_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_adjmDept, txt_adjmDept);  // 정산부서, 정산부서명	
}

scwin.udc_emp2_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_drawEmpNo, txt_drawEmpNm);  // 사원번호, 사원명
}

scwin.udc_AcctDept_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_drawAcctDeptCd, txt_drawAcctDeptNm);  // 작성귀속부서코드, 작성귀속부서명
}

scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
}

scwin.setSum = function (d, fd, r, c) {
    amt = ds_purchaseCerti.getCellData(r, "spplyAmt");
    vat =  ds_purchaseCerti.getCellData(r, "vat");
    var totAmt = amt + vat;
    ds_purchaseCerti.setCellData(r, "EXP_SUM", "totAmt");
    // ds_purchaseCerti.setCellData(r, c, amt + vat);
}

scwin.f_RegistPurchaseEvidence = async function () {
    // Data 변경 여부 조회
    if (ds_certiList.getModifiedJSON().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["목록"]);  // 선택된 @이(가) 없습니다.
        return;
    }

    // 미접수(전표번호 미생성)인 경우만 가능
    var slipNo = "";
    for (var i = 0; i < ds_certiList.getTotalRow(); i++) {
        slipNo = ds_certiList.getCellData(i, "slipNo");
        if (ds_certiList.getCellData(i, "chk") == "T") {
            if (slipNo != "") {
                $c.gus.cfAlertMsg("이미 접수된 건이 포함되어 있습니다.");
                return;
            }
        }
    }

    // 선택건의 공급가액, 부가세 합계 계산
    var spplyAmt = 0;
    var vat = 0;
    for (var i = 0; i < ds_certiList.getTotalRow(); i++) {
        if (ds_certiList.getCellData(i, "chk") == "T") {
            spplyAmt += +ds_certiList.getCellData(i, "spplyAmt");
            vat += +ds_certiList.getCellData(i, "vat");
        }
    }

    // 마이너스 금액은 전표생성할  수 없습니다.
    if (spplyAmt < 0) {
        $c.gus.cfAlertMsg("마이너스 금액은 전표생성할  수 없습니다.");
        return;
    }

    // 정산부서, 전표일자, 증빙구분, 적요, 작성자, 작성귀속부서, 공급일자 체크
    if (!$c.gus.cfValidate([ed_adjmDept, ed_slipDt, lc_evidKndClsCd, lc_taxnClsCd, txt_summary, ed_drawEmpNo, ed_drawAcctDeptCd, ed_spplyDt, rd_elecAuthTrgtYn])) {
        return;
    }

    if (ed_payDt.getValue() != "") {
        if (lc_reqPayMthdCd.getValue() == "") {
            $c.win.alert("지급일을 입력하면 지급 방법도 입력해야 합니다.");
            return;
        }
    }

    if (lc_reqPayMthdCd.getValue() != "") {
        if (ed_payDt.getValue() == "") {
            $c.win.alert("방법을 입력하면 지급일도 입력해야 합니다.");
            return;
        }
    }

    if (await $c.win.confirm(MSG_CM_CRM_001)) {  // 저장하시겠습니까?
        ds_purchaseCerti.setCellData(gr_purchaseCerti.getFocusedRowIndex(), "pchsClntNo", ed_pchsClntNo.getValue());    // 매입거래처
        ds_purchaseCerti.setCellData(gr_purchaseCerti.getFocusedRowIndex(), "busiNo", ds_clntInfo.getCellData(gr_certiList.getFocusedRowIndex(), "busiNo"));  // 사업자번호
        ds_purchaseCerti.setCellData(gr_purchaseCerti.getFocusedRowIndex(), "spplyAmt", spplyAmt);  // 공급금액
        ds_purchaseCerti.setCellData(gr_purchaseCerti.getFocusedRowIndex(), "vat", vat);  // 부가세

        $c.sbm.execute(sbm_saveRegistPurchaseEvidence);
    }
}

scwin.excel = async function () {
    fileName = "세금계산서 접수 등록";
    $c.data.downloadGridViewExcel(gr_certiList, { fileName: fileName, sheetName: fileName });
}
//---------------------------------------------------------
// 컴포넌트 이벤트
//---------------------------------------------------------   

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_RetrieveCertiList();
};

scwin.btn_fieldClear_onclick = function (e) {
    $c.gus.cfInitObjects(tb_mainData);
    scwin.f_SetDefaultData();
};

scwin.btn_save_onclick = function (e) {
    scwin.f_RegistPurchaseEvidence();
};

scwin.sbm_searchCertiList_submitdone = async function () {
    rowCnt = ds_certiList.getTotalRow();
    // 총 조회건수 표시
    ed_totalRow.setValue(rowCnt);

    scwin.f_PchsDataClear();

    if (rowCnt == 0) {
        $c.gus.cfDisableBtnOnly([btn_save]);
        $c.gus.cfDisableObjects([ed_adjmDept, txt_adjmDept, img_PopUp4, ed_slipDt, lc_evidKndClsCd, lc_taxnClsCd, txt_summary, ed_drawEmpNo, txt_drawEmpNm, img_PopUp5, ed_drawAcctDeptCd, txt_drawAcctDeptNm, img_PopUp6, ed_spplyDt, rd_elecAuthTrgtYn]);
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
        ds_purchaseCerti.removeAll();
    } else {
        $c.gus.cfEnableBtnOnly([btn_save]);
        $c.gus.cfEnableObjects([ed_adjmDept, txt_adjmDept, img_PopUp4, ed_slipDt, lc_evidKndClsCd, lc_taxnClsCd, txt_summary, ed_drawEmpNo, txt_drawEmpNm, img_PopUp5, ed_drawAcctDeptCd, txt_drawAcctDeptNm, img_PopUp6, ed_spplyDt, rd_elecAuthTrgtYn]);

        for (var i = 0; i < ds_certiList.getTotalRow(); i++) {
            scwin.loopCnt = i;
            await scwin.f_RetrieveClntInfo(i);  // 매입증빙(상호,사업자번호) 조회
            idx = ds_purchaseCerti.insertRow();
            ds_purchaseCerti.setCellData(idx, "chk", ""); 	//거래명세서 번호
            ds_purchaseCerti.setCellData(idx, "adjmDept", ds_certiList.getCellData(i, "pchsDeptCd")); 	//정산부서
            ds_purchaseCerti.setCellData(idx, "slipDt", scwin.vQryEndDt);
            if (ds_certiList.getCellData(i, "vat") == 0) {
                ds_purchaseCerti.setCellData(idx, "evidKndClsCd", "20");
                ds_purchaseCerti.setCellData(idx, "taxnClsCd", "02");
            } else {
                ds_purchaseCerti.setCellData(idx, "evidKndClsCd", "10");
                ds_purchaseCerti.setCellData(idx, "taxnClsCd", "01");
            }
            ds_purchaseCerti.setCellData(idx, "summary", ds_certiList.getCellData(i, "rmk"));			//적요
            ds_purchaseCerti.setCellData(idx, "pchsClntNo", ds_certiList.getCellData(i, "pchsClntNo"));			//매입거래처
            if (scwin.partner == "P") {
                ds_purchaseCerti.setCellData(idx, "evidKndClsCd", "20");
                ds_purchaseCerti.setCellData(idx, "taxnClsCd", "03");
            }
            if (scwin.inuChk == "1") {
                ds_purchaseCerti.setCellData(idx, "evidKndClsCd", "00");
            }
            ds_purchaseCerti.setCellData(idx, "drawEmpNo", scwin.memJson.empNo);  		// 작성자코드
            ds_purchaseCerti.setCellData(idx, "drawAcctDeptCd", scwin.memJson.acctDeptCd);  	// 작성귀속부서코드

            ds_purchaseCerti.setCellData(idx, "busiNo", lay_busiNo.getValue());  // 사업자번호
            ds_purchaseCerti.setCellData(idx, "spplyDt", ds_certiList.getCellData(i, "pchsIntendDt")); 					//공급일자

            ds_purchaseCerti.setCellData(idx, "spplyAmt", ds_certiList.getCellData(i, "spplyAmt"));	// 공급금액
            ds_purchaseCerti.setCellData(idx, "vat", ds_certiList.getCellData(i, "vat"));			// 부가세

            ds_purchaseCerti.setCellData(idx, "elecAuthTrgtYn", 0);
        }

        gr_purchaseCerti.setFocusedCell(0, 0);
    }
    ed_totalRow2.setValue(ds_purchaseCerti.getTotalRow());
    $c.gus.cfDisableObjects([lc_taxnClsCd]);
}

scwin.sbm_saveRegistPurchaseEvidence_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    $c.gus.cfAlertMsg(MSG_CM_INF_001);	 // 성공적으로 저장하였습니다

    scwin.f_RetrieveCertiList();
}

scwin.gr_certiList_onviewchange = function (info) {
    if (info.colId == "chk") {
        for (var i = 0; i < ds_certiList.getTotalRow(); i++) {
            if (ds_certiList.getCellData(i, "chk") == "T") {
                ds_purchaseCerti.setCellData(i, "chk", ds_certiList.getCellData(i, "certiNo"));
            } else {
                ds_purchaseCerti.setCellData(i, "chk", "");
            }
        }
    }
};

scwin.lc_evidKndClsCd_onviewchange = function (info) {
    if (lc_evidKndClsCd.getValue() == "10") {  // 증빙구분(세금계산서)
        lc_taxnClsCd.setValue("01");  // 과세구분(과세)
        rd_elecAuthTrgtYn.setValue("0");  // 전자세금계산서(미적용)
        $c.gus.cfEnableObjects([rd_elecAuthTrgtYn]);
        $c.gus.cfDisableObjects([lc_taxnClsCd]);
    } else if (lc_evidKndClsCd.getValue() == "00") {  // 증빙구분(기타-부가세없음)
        lc_taxnClsCd.setValue("02");  // 과세구분(영세)
        rd_elecAuthTrgtYn.setValue("0");  // 전자세금계산서(미적용)
        $c.gus.cfDisableObjects([rd_elecAuthTrgtYn]);
        $c.gus.cfDisableObjects([lc_taxnClsCd]);
    } else {
        lc_taxnClsCd.setValue("");  // 과세구분(선택)
        rd_elecAuthTrgtYn.setValue("0");  // 전자세금계산서(미적용)
        $c.gus.cfDisableObjects([lc_taxnClsCd, rd_elecAuthTrgtYn]);
        $c.gus.cfEnableObjects([lc_taxnClsCd]);
    }
};

